CONTROL_SPECS: dict[int, dict[str, Any]] = {number: {"title": title, "slug": slug, "tables": tables, "fields": fields, "ui": ui, "route": route, "dependencies": deps} for number, title, slug, tables, fields, ui, route, deps in _SPEC_ROWS}
_EMPTY_ALLOWED_FIELDS = ("reviewer_feedback", "tenant_exclusions", "residual_alert", "remediation_exception", "billing_disputes")


def _digest(value: object) -> str:
    return hashlib.sha256(repr(value).encode("utf-8")).hexdigest()


def _resolve(capability: Improve1Capability | str | int) -> Improve1Capability | None:
    if isinstance(capability, Improve1Capability):
        return capability
    if isinstance(capability, int):
        return CAPABILITY_BY_NUMBER.get(capability)
    return CAPABILITY_BY_SLUG.get(capability)


def sample_payload_for(capability: Improve1Capability | str | int) -> dict[str, Any]:
    resolved = _resolve(capability)
    if resolved is None:
        return {}
    spec = CONTROL_SPECS[resolved.feature_number]
    payload = {field: f"{resolved.slug}_{field}" for field in spec["fields"]}
    payload.update({
        "rollup_validation": "passed", "residual_status": "explained", "read_quality": "observed", "dst_handling": "resolved", "health_status": "live", "active_use_allowed": True,
        "service_mapping_approved": True, "revision_permission": "approved", "tariff_calendar_valid": True, "determinant_computed": True, "non_mutating_scenario": True,
        "resolved_schedule": "deterministic", "override_explanation": "weather driven", "overlap_status": "none", "direct_device_write_blocked": True,
        "expiry_time": "2026-06-01T00:00:00Z", "expired_override_effect": "ignored", "shed_eligibility": "exempt", "blocked_recommendation": True,
        "reviewer_approval": "approved", "overlap_check": "clear", "weather_effect": "separated", "operational_effect": "separated", "exception_queue_route": "energy_ops",
        "peak_likelihood_score": 0.82, "protected_load_rejected": True, "dispatch_state": "settled", "state_transition_valid": True, "settlement_summary": "ready",
        "shed_plan_blocked": True, "rebound_peak_controlled": True, "historical_period_rewrite_blocked": True, "audit_weight_record": "captured", "overlap_prevention": "passed",
        "loss_tolerance_band": "within", "retrofit_status": "verified", "decay_threshold": "not_exceeded", "non_mutating_api": True, "source_span_citations": ("tariff-page-2",),
        "human_approval_required": True, "mutation_requires_approval": True, "evidence_complete": True, "tenant_scope_permission": "scoped", "non_mutating_results": True,
        "event_order": "predictable", "exactly_once_business_effect": True, "cross_tenant_negative_test": "passed", "safe_bounds": "passed", "high_severity_passed": True,
        "core_key_collision_blocked": True, "approval_state": "approved", "high_risk_blocked_when_stale": True, "manual_database_edits_absent": True, "release_signoff": "signed",
        "stream_engine_picker_visible": False,
    })
    return payload


def _domain_findings(capability: Improve1Capability, payload: dict[str, Any]) -> tuple[str, ...]:
    findings: list[str] = []
    n = capability.feature_number
    if n == 1 and payload.get("rollup_validation") != "passed": findings.append("meter topology residual reconciliation failed")
    if n == 2 and payload.get("dst_handling") != "resolved": findings.append("interval reads must handle daylight-saving boundaries")
    if n == 3 and (payload.get("health_status") in {"stale", "decommissioned"} or payload.get("active_use_allowed") is not True): findings.append("stale or decommissioned meters cannot be active")
    if n == 4 and payload.get("service_mapping_approved") is not True: findings.append("energy meter requires approved utility service mapping")
    if n == 5 and payload.get("revision_permission") != "approved": findings.append("estimated-read corrections require governed approval")
    if n == 6 and payload.get("tariff_calendar_valid") is not True: findings.append("tariff calendar is ambiguous")
    if n == 7 and payload.get("determinant_computed") is not True: findings.append("demand determinant was not computed")
    if n == 8 and payload.get("non_mutating_scenario") is not True: findings.append("tariff scenarios must be non-mutating")
    if n == 11 and payload.get("overlap_status") != "none": findings.append("equipment schedule conflict is unresolved")
    if n == 12 and payload.get("direct_device_write_blocked") is not True: findings.append("optimization cannot write directly to devices")
    if n == 13 and payload.get("expired_override_effect") != "ignored": findings.append("expired overrides must stop influencing schedules")
    if n == 14 and payload.get("blocked_recommendation") is not True: findings.append("critical loads require blocked shed recommendations")
    if n == 15 and payload.get("overlap_check") != "clear": findings.append("baseline versions cannot overlap")
    if n == 21 and payload.get("protected_load_rejected") is not True: findings.append("demand response enrollment must reject protected loads")
    if n == 22 and payload.get("state_transition_valid") is not True: findings.append("demand response dispatch state transition is invalid")
    if n == 24 and payload.get("shed_plan_blocked") is not True: findings.append("comfort and safety guardrails must block unsafe shed plans")
    if n == 25 and payload.get("rebound_peak_controlled") is not True: findings.append("post-event rebound is uncontrolled")
    if n == 26 and payload.get("historical_period_rewrite_blocked") is not True: findings.append("carbon factor revisions cannot rewrite historical periods")
    if n == 33 and (not payload.get("source_span_citations") or payload.get("human_approval_required") is not True): findings.append("document intake requires source citations and human approval")
    if n == 34 and payload.get("mutation_requires_approval") is not True: findings.append("anomaly triage agent cannot mutate without approval")
    if n == 35 and payload.get("evidence_complete") is not True: findings.append("tenant allocation explanation requires complete evidence")
    if n == 40 and payload.get("non_mutating_results") is not True: findings.append("validate/simulate API routes must be non-mutating")
    if n == 42 and payload.get("exactly_once_business_effect") is not True: findings.append("replay-safe eventing must preserve exactly-once business effect")
    if n == 43 and payload.get("cross_tenant_negative_test") != "passed": findings.append("tenant isolation negative test failed")
    if n == 44 and payload.get("safe_bounds") != "passed": findings.append("runtime parameter safe bounds failed")
    if n == 45 and payload.get("high_severity_passed") is not True: findings.append("continuous controls must pass all high-severity assertions")
    if n == 46 and payload.get("core_key_collision_blocked") is not True: findings.append("schema extensions cannot collide with core keys")
    if n == 48 and payload.get("high_risk_blocked_when_stale") is not True: findings.append("stale consumed events must block high-risk recommendations")
    if n == 50 and (payload.get("manual_database_edits_absent") is not True or payload.get("release_signoff") != "signed"): findings.append("end-to-end release drill lacks sign-off or used manual database edits")
    if payload.get("stream_engine_picker_visible"): findings.append("ordinary PBCs must not expose stream-engine pickers")
    return tuple(findings)


def evaluate_energy_control(capability: Improve1Capability | str | int, payload: dict[str, Any] | None = None) -> dict[str, Any]:
    resolved = _resolve(capability)
    if resolved is None:
        return {"ok": False, "reason": "unknown_capability", "side_effects": ()}
    spec = CONTROL_SPECS[resolved.feature_number]
    candidate = sample_payload_for(resolved)
    candidate.update(dict(payload or {}))
    missing_fields = tuple(field for field in spec["fields"] if field not in _EMPTY_ALLOWED_FIELDS and candidate.get(field) in (None, "", (), []))
    foreign_tables = tuple(table for table in spec["tables"] if table not in ENERGY_CONTROL_OWNED_TABLES)
    undeclared_dependencies = tuple(dependency for dependency in spec["dependencies"] if dependency not in ENERGY_CONTROL_DECLARED_DEPENDENCIES)
    findings = _domain_findings(resolved, candidate)
    evidence = {
        "evidence_id": _digest((PBC_KEY, resolved.feature_number, tuple(sorted(candidate))))[:20],
        "owned_tables": spec["tables"],
        "required_fields": spec["fields"],
        "ui_surface": spec["ui"],
        "service_api": spec["route"],
        "test": "tests/test_domain_behavior.py",
        "event_contract": EVENT_CONTRACT,
        "required_event_topic": ENERGY_CONTROL_REQUIRED_EVENT_TOPIC,
        "allowed_database_backends": ENERGY_CONTROL_ALLOWED_DATABASE_BACKENDS,
        "declared_dependencies": spec["dependencies"],
        "side_effects": (),
    }
    ok = not missing_fields and not foreign_tables and not undeclared_dependencies and not findings
    return {"ok": ok, "pbc": PBC_KEY, "feature_number": resolved.feature_number, "slug": resolved.slug, "title": resolved.title, "capability": resolved.as_traceability_row(), "payload": candidate, "evidence": evidence, "missing_fields": missing_fields, "foreign_tables": foreign_tables, "undeclared_dependencies": undeclared_dependencies, "findings": findings, "side_effects": ()}


def improve1_energy_control_contract() -> dict[str, Any]:
    evaluations = tuple(evaluate_energy_control(capability) for capability in ENERGY_CONTROL_CAPABILITIES)
    blocking = tuple(item for item in evaluations if not item["ok"])
    return {"ok": not blocking, "pbc": PBC_KEY, "format": "appgen.facility-energy-management-improve1-control.v1", "capability_count": len(evaluations), "capabilities": evaluations, "owned_tables": ENERGY_CONTROL_OWNED_TABLES, "declared_dependencies": ENERGY_CONTROL_DECLARED_DEPENDENCIES, "allowed_database_backends": ENERGY_CONTROL_ALLOWED_DATABASE_BACKENDS, "event_contract": EVENT_CONTRACT, "required_event_topic": ENERGY_CONTROL_REQUIRED_EVENT_TOPIC, "stream_engine_picker_visible": False, "blocking_gaps": blocking, "side_effects": ()}


ENERGY_CONTROL_FUNCTIONS = {capability.slug: (lambda payload=None, slug=capability.slug: evaluate_energy_control(slug, payload)) for capability in ENERGY_CONTROL_CAPABILITIES}
